'use client'
import { useSignal, useSignals, cn } from '@cascivo/core'
import { useRef } from 'react'
import type { HTMLAttributes } from 'react'
import { t, builtin } from '@cascivo/i18n'
import styles from './tags-input.module.css'

export interface TagsInputProps extends Omit<HTMLAttributes<HTMLDivElement>, 'onChange'> {
  value: string[]
  onValueChange: (v: string[]) => void
  placeholder?: string
  validate?: (tag: string) => boolean
  max?: number
  disabled?: boolean
}

export function TagsInput({
  value,
  onValueChange,
  placeholder,
  validate,
  max,
  disabled = false,
  className,
  ...props
}: TagsInputProps) {
  useSignals()
  const inputValue = useSignal('')
  const inputRef = useRef<HTMLInputElement>(null)

  function addTag(raw: string) {
    const tag = raw.trim()
    if (!tag) return
    if (max !== undefined && value.length >= max) return
    if (value.includes(tag)) return
    if (validate && !validate(tag)) return
    onValueChange([...value, tag])
    inputValue.value = ''
  }

  function removeTag(index: number) {
    onValueChange(value.filter((_, i) => i !== index))
  }

  const placeholderText = placeholder ?? t(builtin.tagsInput.placeholder)

  return (
    <div
      className={cn(styles['wrapper'], className)}
      data-disabled={disabled ? '' : undefined}
      onClick={() => inputRef.current?.focus()}
      {...props}
    >
      {value.map((tag, i) => {
        const isInvalid = validate ? !validate(tag) : false
        return (
          <span key={i} className={styles['tag']} data-state={isInvalid ? 'invalid' : undefined}>
            {tag}
            <button
              type="button"
              className={styles['dismiss']}
              aria-label={t(builtin.tagsInput.remove, { tag })}
              disabled={disabled}
              onClick={(e) => {
                e.stopPropagation()
                removeTag(i)
              }}
            >
              <span aria-hidden="true">×</span>
            </button>
          </span>
        )
      })}
      <input
        ref={inputRef}
        className={styles['input']}
        value={inputValue.value}
        aria-label={t(builtin.tagsInput.label)}
        placeholder={value.length === 0 ? placeholderText : undefined}
        disabled={disabled}
        onChange={(e) => {
          inputValue.value = e.currentTarget.value
        }}
        onKeyDown={(e) => {
          if (e.key === 'Enter' || e.key === ',') {
            e.preventDefault()
            addTag(inputValue.value)
          } else if (e.key === 'Backspace' && !inputValue.value) {
            removeTag(value.length - 1)
          }
        }}
        onBlur={() => {
          if (inputValue.value) addTag(inputValue.value)
        }}
      />
    </div>
  )
}

@layer cascivo.component {
  .wrapper {
    display: flex;
    flex-wrap: wrap;
    gap: var(--cascivo-space-1);
    min-height: 2.5rem;
    padding: var(--cascivo-space-2);
    background-color: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-field);
    cursor: text;
    transition:
      border-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      box-shadow var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:focus-within {
      border-color: var(--cascivo-color-accent);
      box-shadow: var(--cascivo-focus-ring);
    }

    /* Dim via muted colors, not opacity: a 0.5 wrapper opacity dropped the tag
       text below the WCAG contrast threshold. */
    &[data-disabled] {
      cursor: not-allowed;
      background-color: var(--cascivo-color-bg-subtle);
    }

    &[data-disabled] .tag {
      color: var(--cascivo-color-text-muted);
      border-color: var(--cascivo-color-border);
    }
  }

  .tag {
    display: inline-flex;
    align-items: center;
    gap: var(--cascivo-space-1);
    padding-block: var(--cascivo-space-0-5);
    padding-inline: var(--cascivo-space-2);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text);
    background-color: var(--cascivo-color-bg-subtle);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-full);
    line-height: 1.25;

    &[data-state='invalid'] {
      color: var(--cascivo-color-destructive);
      background-color: rgb(from var(--cascivo-color-destructive) r g b / 0.08);
      border-color: var(--cascivo-color-destructive);
    }
  }

  .dismiss {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1rem;
    height: 1rem;
    padding: 0;
    background: none;
    border: none;
    border-radius: var(--cascivo-radius-full);
    color: var(--cascivo-color-text-muted);
    cursor: pointer;
    font-size: var(--cascivo-text-sm);
    line-height: 1;

    &:hover {
      color: var(--cascivo-color-text);
      background-color: var(--cascivo-color-border);
    }

    &:focus-visible {
      outline: 2px solid var(--cascivo-color-accent);
      outline-offset: 1px;
    }

    &:disabled {
      cursor: not-allowed;
    }
  }

  .input {
    flex: 1;
    min-width: 4rem;
    background: none;
    border: none;
    outline: none;
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text);

    &::placeholder {
      color: var(--cascivo-color-text-muted);
    }

    &:disabled {
      cursor: not-allowed;
    }
  }
}
